def build_dataloaders(data_dir: str, image_size: int, batch_size: int, workers: int) -> Tuple[DataLoader, DataLoader, int]:
    train_t, val_t = build_transforms(image_size)

    train_dir = os.path.join(data_dir, "train")
    val_dir = os.path.join(data_dir, "val")
    if not os.path.isdir(train_dir) or not os.path.isdir(val_dir):
        raise FileNotFoundError(f"Expected ImageFolder structure: {data_dir}/train and {data_dir}/val")

